// Definition for singly-linked list node
class ListNode {
    constructor(val = 0, next = null) {
        this.val = val;
        this.next = next;
    }
}

class MinHeap {
    constructor() {
        // Array to simulate heap
        this.heap = [];
    }

    // Function to insert a node into the min-heap
    insert(node) {
        // Add the node at the end
        this.heap.push(node);
        // Restore heap property by bubbling up
        this.bubbleUp(this.heap.length - 1);
    }

    // Function to return the smallest node (top of heap)
    getMin() {
        return this.heap[0];
    }

    // Function to remove and return the smallest node
    extractMin() {
        if (this.heap.length === 0) return null;
        // Swap first and last elements
        const min = this.heap[0];
        const end = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = end;
            // Restore heap property by bubbling down
            this.bubbleDown(0);
        }
        return min;
    }

    // Bubble up the element at index i to its correct position
    bubbleUp(i) {
        let currentIndex = i;
        while (currentIndex > 0) {
            // Find parent index
            let parentIndex = Math.floor((currentIndex - 1) / 2);
            // If current node value is less than parent, swap
            if (this.heap[currentIndex].val < this.heap[parentIndex].val) {
                [this.heap[currentIndex], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[currentIndex]];
                currentIndex = parentIndex;
            } else break;
        }
    }

    // Bubble down the element at index i to maintain heap
    bubbleDown(i) {
        let currentIndex = i;
        const length = this.heap.length;
        while (true) {
            let left = 2 * currentIndex + 1;
            let right = 2 * currentIndex + 2;
            let smallest = currentIndex;

            // Compare with left child
            if (left < length && this.heap[left].val < this.heap[smallest].val) {
                smallest = left;
            }
            // Compare with right child
            if (right < length && this.heap[right].val < this.heap[smallest].val) {
                smallest = right;
            }

            // If smallest is not current index, swap and continue
            if (smallest !== currentIndex) {
                [this.heap[currentIndex], this.heap[smallest]] = [this.heap[smallest], this.heap[currentIndex]];
                currentIndex = smallest;
            } else break;
        }
    }

    // Return size of heap
    size() {
        return this.heap.length;
    }
}

class Solution {
    /**
     * Function to merge k sorted linked lists into a single sorted list
     * @param {ListNode[]} lists - Array of k sorted linked list heads
     * @return {ListNode} - Head of merged sorted linked list
     */
    mergeKSortedLists(lists) {
        // Create a new min heap to keep track of the smallest nodes
        const heap = new MinHeap();

        // Push the head node of each list into the heap
        for (let node of lists) {
            if (node !== null) {
                heap.insert(node);
            }
        }

        // Create a dummy head for the merged list
        const dummy = new ListNode(0);
        let current = dummy;

        // Repeat while heap is not empty
        while (heap.size() > 0) {
            // Extract node with the smallest value
            const smallest = heap.extractMin();

            // Add this node to the merged list
            current.next = smallest;
            current = current.next;

            // If this node has a next node, push it into heap
            if (smallest.next !== null) {
                heap.insert(smallest.next);
            }
        }

        // Return the actual head of merged list
        return dummy.next;
    }
}

